async (page) => {
  // Set attack style to Hack (6) for continued Strength XP
  await page.evaluate(() => window.game.player.setAttackStyle(6));
  await page.waitForTimeout(500);
  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    return { pos: s.player_position, hp: s.player_stats.hp, max_hp: s.player_stats.max_hp, equipment: s.equipment, skills: s.skills, inventory: s.inventory };
  });
  return JSON.stringify(state);
}

async (page) => {
  // Navigate west toward Village Girl (136,146) in increments
  // Player at (188,158) - need to reach (136,146). Go west in steps.
  const steps = [
    {x: 175, y: 155},  // step 1 - nearby, on screen
    {x: 162, y: 150},  // step 2
    {x: 148, y: 147},  // step 3  
    {x: 137, y: 146},  // final - next to Village Girl
  ];

  let lastPos = {x: 188, y: 158};
  for (const step of steps) {
    const result = await page.evaluate(({x, y}) => JSON.stringify(window.__clickTile(x, y)), step);
    await page.waitForTimeout(3000);
    const pos = await page.evaluate(() => window.__latestGameState.player_position);
    if (pos.x === lastPos.x && pos.y === lastPos.y) {
      // Not moving, try clicking on canvas manually
      break;
    }
    lastPos = pos;
  }

  const finalState = await page.evaluate(() => {
    const s = window.__latestGameState;
    return { pos: s.player_position, nearby_npcs: s.nearby_entities.filter(e => e.type === 1).slice(0,5).map(e => ({name: e.name, dist: e.distance, quest: e.quest_npc})) };
  });
  return JSON.stringify(finalState);
}

async (page) => {
  // Click at far left of canvas to walk left ~13 tiles per click
  // Repeat until near Village Girl at (136, 146)
  const clickLeft = async (yOffset = 0) => {
    await page.evaluate(({y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', {
        clientX: 20, clientY: 350 + y, bubbles: true, ctrlKey: false
      }));
    }, {y: yOffset});
    await page.waitForTimeout(3500);
  };

  let pos = await page.evaluate(() => window.__latestGameState.player_position);
  console.log('start:', JSON.stringify(pos));

  // Click left repeatedly until x < 145
  for (let i = 0; i < 8 && pos.x > 140; i++) {
    await clickLeft(-20); // slight up
    pos = await page.evaluate(() => window.__latestGameState.player_position);
  }

  const finalState = await page.evaluate(() => {
    const s = window.__latestGameState;
    return { pos: s.player_position, near_vg: s.nearby_entities.filter(e=>e.name==='Village Girl').map(e=>({dist:e.distance,id:e.id})) };
  });
  return JSON.stringify(finalState);
}

async (page) => {
  const clickDir = async (cx, cy) => {
    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', {
        clientX: x, clientY: y, bubbles: true, ctrlKey: false
      }));
    }, {x: cx, y: cy});
    await page.waitForTimeout(3500);
  };

  let pos = await page.evaluate(() => window.__latestGameState.player_position);

  // Click upper-left to get to (136,146)
  for (let i = 0; i < 6 && (pos.x > 138 || pos.y > 148); i++) {
    await clickDir(20, 320); // upper-left
    pos = await page.evaluate(() => window.__latestGameState.player_position);
  }

  const finalState = await page.evaluate(() => {
    const s = window.__latestGameState;
    const vg = s.nearby_entities.find(e=>e.name==='Village Girl');
    return { pos: s.player_position, vg_dist: vg ? vg.distance : null, vg_id: vg ? vg.id : null, vg_on_screen: vg ? vg.on_screen : null };
  });
  return JSON.stringify(finalState);
}

